@startuml
!theme plain

package "patient" as patient {
  package "care" as care {
    [Box] as Box
    [BoxDAO] as BoxDAO
    [Date] as Date
    [Doctor] as Doctor
    [Patient] as Patient
    [PatientsForm] as PatientsForm
    [DoctorDAO] as DoctorDAO
    [PatientCare] as PatientCare
    [PatientDAO] as PatientDAO
    [Person] as Person
  }
}

package "com" as com {
  package "sun" as sun {
    package "glass" as glass {
      package "events" as events {
        [KeyEvent] as KeyEvent
      }
    }
  }
}

package "java" as java {
  package "util" as util {
    [ArrayList] as ArrayList
    [Calendar] as Calendar
  }
}

package "javax" as javax {
  package "swing" as swing {
    [JComboBox] as JComboBox
    [JFrame] as JFrame
    [JOptionPane] as JOptionPane
  }
}

Doctor --> Person
Patient --> Person
PatientsForm --> JFrame

@enduml
